tailwind.config.ts.content:
import type { Config } from "tailwindcss";

export default {
  darkMode: ["class"],
  content: ["./client/index.html", "./client/src/**/*.{js,jsx,ts,tsx}"],
  theme: {
    extend: {
      borderRadius: {
        lg: ".5625rem", /* 9px */
        md: ".375rem", /* 6px */
        sm: ".1875rem", /* 3px */
      },
      colors: {
        // Flat / base colors (regular buttons)
        background: "hsl(var(--background) / <alpha-value>)",
        foreground: "hsl(var(--foreground) / <alpha-value>)",
        border: "hsl(var(--border) / <alpha-value>)",
        input: "hsl(var(--input) / <alpha-value>)",
        card: {
          DEFAULT: "hsl(var(--card) / <alpha-value>)",
          foreground: "hsl(var(--card-foreground) / <alpha-value>)",
          border: "hsl(var(--card-border) / <alpha-value>)",
        },
        popover: {
          DEFAULT: "hsl(var(--popover) / <alpha-value>)",
          foreground: "hsl(var(--popover-foreground) / <alpha-value>)",
          border: "hsl(var(--popover-border) / <alpha-value>)",
        },
        primary: {
          DEFAULT: "hsl(var(--primary) / <alpha-value>)",
          foreground: "hsl(var(--primary-foreground) / <alpha-value>)",
          border: "var(--primary-border)",
        },
        secondary: {
          DEFAULT: "hsl(var(--secondary) / <alpha-value>)",
          foreground: "hsl(var(--secondary-foreground) / <alpha-value>)",
          border: "var(--secondary-border)",
        },
        muted: {
          DEFAULT: "hsl(var(--muted) / <alpha-value>)",
          foreground: "hsl(var(--muted-foreground) / <alpha-value>)",
          border: "var(--muted-border)",
        },
        accent: {
          DEFAULT: "hsl(var(--accent) / <alpha-value>)",
          foreground: "hsl(var(--accent-foreground) / <alpha-value>)",
          border: "var(--accent-border)",
        },
        destructive: {
          DEFAULT: "hsl(var(--destructive) / <alpha-value>)",
          foreground: "hsl(var(--destructive-foreground) / <alpha-value>)",
          border: "var(--destructive-border)",
        },
        ring: "hsl(var(--ring) / <alpha-value>)",
        chart: {
          "1": "hsl(var(--chart-1) / <alpha-value>)",
          "2": "hsl(var(--chart-2) / <alpha-value>)",
          "3": "hsl(var(--chart-3) / <alpha-value>)",
          "4": "hsl(var(--chart-4) / <alpha-value>)",
          "5": "hsl(var(--chart-5) / <alpha-value>)",
        },
        sidebar: {
          ring: "hsl(var(--sidebar-ring) / <alpha-value>)",
          DEFAULT: "hsl(var(--sidebar) / <alpha-value>)",
          foreground: "hsl(var(--sidebar-foreground) / <alpha-value>)",
          border: "hsl(var(--sidebar-border) / <alpha-value>)",
        },
        "sidebar-primary": {
          DEFAULT: "hsl(var(--sidebar-primary) / <alpha-value>)",
          foreground: "hsl(var(--sidebar-primary-foreground) / <alpha-value>)",
          border: "var(--sidebar-primary-border)",
        },
        "sidebar-accent": {
          DEFAULT: "hsl(var(--sidebar-accent) / <alpha-value>)",
          foreground: "hsl(var(--sidebar-accent-foreground) / <alpha-value>)",
          border: "var(--sidebar-accent-border)"
        },
        status: {
          online: "rgb(34 197 94)",
          away: "rgb(245 158 11)",
          busy: "rgb(239 68 68)",
          offline: "rgb(156 163 175)",
        },
      },
      fontFamily: {
        sans: ["var(--font-sans)"],
        serif: ["var(--font-serif)"],
        mono: ["var(--font-mono)"],
      },
      keyframes: {
        "accordion-down": {
          from: { height: "0" },
          to: { height: "var(--radix-accordion-content-height)" },
        },
        "accordion-up": {
          from: { height: "var(--radix-accordion-content-height)" },
          to: { height: "0" },
        },
      },
      animation: {
        "accordion-down": "accordion-down 0.2s ease-out",
        "accordion-up": "accordion-up 0.2s ease-out",
      },
    },
  },
  plugins: [require("tailwindcss-animate"), require("@tailwindcss/typography")],
} satisfies Config;

vite.config.ts.content:
import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";
import path from "path";
import runtimeErrorOverlay from "@replit/vite-plugin-runtime-error-modal";

export default defineConfig({
  plugins: [
    react(),
    runtimeErrorOverlay(),
    ...(process.env.NODE_ENV !== "production" &&
    process.env.REPL_ID !== undefined
      ? [
          await import("@replit/vite-plugin-cartographer").then((m) =>
            m.cartographer(),
          ),
          await import("@replit/vite-plugin-dev-banner").then((m) =>
            m.devBanner(),
          ),
        ]
      : []),
  ],
  resolve: {
    alias: {
      "@": path.resolve(import.meta.dirname, "client", "src"),
      "@shared": path.resolve(import.meta.dirname, "shared"),
      "@assets": path.resolve(import.meta.dirname, "attached_assets"),
    },
  },
  root: path.resolve(import.meta.dirname, "client"),
  build: {
    outDir: path.resolve(import.meta.dirname, "dist/public"),
    emptyOutDir: true,
  },
  server: {
    allowedHosts: true,
    fs: {
      strict: true,
      deny: ["**/.*"],
    },
  },
});

drizzle.config.ts.content:
import { defineConfig } from "drizzle-kit";

if (!process.env.DATABASE_URL) {
  throw new Error("DATABASE_URL, ensure the database is provisioned");
}

export default defineConfig({
  out: "./migrations",
  schema: "./shared/schema.ts",
  dialect: "postgresql",
  dbCredentials: {
    url: process.env.DATABASE_URL,
  },
});

client/src/index.css.content:
@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    /* Fonts */
    --font-sans: "Inter", system-ui, -apple-system, sans-serif;
    --font-serif: "Georgia", serif;
    --font-mono: "Consolas", "Monaco", monospace;

    /* Base colors (light mode - not used in this app, but required) */
    --background: 0 0% 100%;
    --foreground: 222.2 84% 4.9%;

    --card: 0 0% 100%;
    --card-foreground: 222.2 84% 4.9%;
    --card-border: 214.3 31.8% 91.4%;

    --popover: 0 0% 100%;
    --popover-foreground: 222.2 84% 4.9%;
    --popover-border: 214.3 31.8% 91.4%;

    --primary: 217 91% 60%;
    --primary-foreground: 210 40% 98%;
    --primary-border: hsl(217 91% 55%);

    --secondary: 210 40% 96.1%;
    --secondary-foreground: 222.2 47.4% 11.2%;
    --secondary-border: hsl(214.3 31.8% 91.4%);

    --muted: 210 40% 96.1%;
    --muted-foreground: 215.4 16.3% 46.9%;
    --muted-border: hsl(214.3 31.8% 91.4%);

    --accent: 189 94% 43%;
    --accent-foreground: 222.2 47.4% 11.2%;
    --accent-border: hsl(189 94% 38%);

    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 210 40% 98%;
    --destructive-border: hsl(0 84.2% 55%);

    --border: 214.3 31.8% 91.4%;
    --input: 214.3 31.8% 91.4%;
    --ring: 217 91% 60%;

    --chart-1: 12 76% 61%;
    --chart-2: 173 58% 39%;
    --chart-3: 197 37% 24%;
    --chart-4: 43 74% 66%;
    --chart-5: 27 87% 67%;

    --sidebar: 0 0% 98%;
    --sidebar-foreground: 240 5.3% 26.1%;
    --sidebar-border: 220 13% 91%;
    --sidebar-ring: 217 91% 60%;

    --sidebar-primary: 217 91% 60%;
    --sidebar-primary-foreground: 210 40% 98%;
    --sidebar-primary-border: hsl(217 91% 55%);

    --sidebar-accent: 210 40% 96.1%;
    --sidebar-accent-foreground: 222.2 47.4% 11.2%;
    --sidebar-accent-border: hsl(214.3 31.8% 91.4%);

    --radius: 0.5rem;
  }

  .dark {
    /* Dark mode colors (primary theme for Auto Wiki) */
    --background: 222 47% 11%;
    --foreground: 210 40% 98%;

    --card: 217 33% 17%;
    --card-foreground: 210 40% 98%;
    --card-border: 215 28% 25%;

    --popover: 217 33% 17%;
    --popover-foreground: 210 40% 98%;
    --popover-border: 215 28% 25%;

    --primary: 217 91% 60%;
    --primary-foreground: 222 47% 11%;
    --primary-border: hsl(217 91% 65%);

    --secondary: 217 33% 20%;
    --secondary-foreground: 210 40% 98%;
    --secondary-border: hsl(215 28% 28%);

    --muted: 217 33% 20%;
    --muted-foreground: 215 20% 65%;
    --muted-border: hsl(215 28% 28%);

    --accent: 189 94% 43%;
    --accent-foreground: 210 40% 98%;
    --accent-border: hsl(189 94% 48%);

    --destructive: 0 62.8% 30.6%;
    --destructive-foreground: 210 40% 98%;
    --destructive-border: hsl(0 62.8% 35%);

    --border: 215 28% 25%;
    --input: 215 28% 25%;
    --ring: 217 91% 60%;

    --chart-1: 220 70% 50%;
    --chart-2: 160 60% 45%;
    --chart-3: 30 80% 55%;
    --chart-4: 280 65% 60%;
    --chart-5: 340 75% 55%;

    --sidebar: 222 47% 11%;
    --sidebar-foreground: 210 40% 98%;
    --sidebar-border: 215 28% 20%;
    --sidebar-ring: 217 91% 60%;

    --sidebar-primary: 217 91% 60%;
    --sidebar-primary-foreground: 222 47% 11%;
    --sidebar-primary-border: hsl(217 91% 65%);

    --sidebar-accent: 217 33% 20%;
    --sidebar-accent-foreground: 210 40% 98%;
    --sidebar-accent-border: hsl(215 28% 28%);
  }
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply bg-background text-foreground;
    font-feature-settings: "rlig" 1, "calt" 1;
  }
}

@layer utilities {
  /* Hover elevation utility - subtle background lift on hover */
  .hover-elevate {
    @apply transition-colors duration-200;
  }

  .hover-elevate:hover {
    filter: brightness(1.1);
  }

  /* Active elevation utility - more dramatic background lift on press */
  .active-elevate-2 {
    @apply transition-all duration-100;
  }

  .active-elevate-2:active {
    filter: brightness(0.9);
    transform: scale(0.98);
  }

  /* Toggle utilities */
  .toggle-elevate {
    @apply transition-colors duration-200;
  }

  .toggle-elevated {
    filter: brightness(1.2);
  }

  /* Remove default hover/active elevations */
  .no-default-hover-elevate:hover {
    filter: none;
  }

  .no-default-active-elevate:active {
    filter: none;
    transform: none;
  }
}

client/src/App.tsx.content:
import { Route, Router } from "wouter";
import { AuthProvider } from "./lib/auth";
import Home from "./pages/Home";
import Cars from "./pages/Cars";
import CarDetail from "./pages/CarDetail";
import Compare from "./pages/Compare";
import Blog from "./pages/Blog";
import BlogPost from "./pages/BlogPost";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Admin from "./pages/Admin";
import Contact from "./pages/Contact";
import About from "./pages/About";
import Navbar from "./components/Navbar";
import Footer from "./components/Footer";

function App() {
  return (
    <AuthProvider>
      <div className="min-h-screen flex flex-col bg-slate-950 text-white">
        <Navbar />
        <main className="flex-1">
          <Router>
            <Route path="/" component={Home} />
            <Route path="/automobili" component={Cars} />
            <Route path="/automobili/:id" component={CarDetail} />
            <Route path="/usporedi" component={Compare} />
            <Route path="/blog" component={Blog} />
            <Route path="/blog/:id" component={BlogPost} />
            <Route path="/prijava" component={Login} />
            <Route path="/registracija" component={Register} />
            <Route path="/admin" component={Admin} />
            <Route path="/kontakt" component={Contact} />
            <Route path="/o-nama" component={About} />
          </Router>
        </main>
        <Footer />
      </div>
    </AuthProvider>
  );
}

export default App;

client/src/pages/Admin.tsx.content:
import { useState, useEffect } from "react";
import { useAuth } from "../lib/auth";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useLocation } from "wouter";
import type { Car, BlogPost, ContactMessage } from "@shared/schema";
import { Plus, Edit, Trash2, X } from "lucide-react";

export default function Admin() {
  const { user } = useAuth();
  const [, setLocation] = useLocation();
  const [activeTab, setActiveTab] = useState<"cars" | "blog" | "messages">("cars");
  const [showCarForm, setShowCarForm] = useState(false);
  const [showBlogForm, setShowBlogForm] = useState(false);
  const [editingCar, setEditingCar] = useState<Car | null>(null);
  const [editingBlog, setEditingBlog] = useState<BlogPost | null>(null);
  const queryClient = useQueryClient();

  useEffect(() => {
    if (!user || user.role !== "admin") {
      setLocation("/");
    }
  }, [user, setLocation]);

  if (!user || user.role !== "admin") {
    return null;
  }

  const { data: cars } = useQuery<Car[]>({ queryKey: ["/api/cars"] });
  const { data: posts } = useQuery<BlogPost[]>({ queryKey: ["/api/blog"] });
  const { data: messages } = useQuery<ContactMessage[]>({ queryKey: ["/api/contact"] });

  const deleteCar = useMutation({
    mutationFn: async (id: string) => {
      const res = await fetch(`/api/cars/${id}`, { method: "DELETE" });
      if (!res.ok) throw new Error("Failed to delete");
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["/api/cars"] }),
  });

  const deleteBlog = useMutation({
    mutationFn: async (id: string) => {
      const res = await fetch(`/api/blog/${id}`, { method: "DELETE" });
      if (!res.ok) throw new Error("Failed to delete");
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["/api/blog"] }),
  });

  return (
    <div className="min-h-screen py-12">
      <div className="container mx-auto px-4 max-w-7xl">
        <h1 className="text-4xl font-bold mb-8 text-center bg-gradient-to-r from-blue-400 to-cyan-400 bg-clip-text text-transparent">
          Admin Panel
        </h1>

        <div className="flex space-x-2 mb-8">
          <button
            onClick={() => setActiveTab("cars")}
            className={`px-6 py-3 rounded-lg font-semibold transition ${
              activeTab === "cars"
                ? "bg-blue-600 text-white"
                : "bg-slate-800 text-slate-300 hover:bg-slate-700"
            }`}
          >
            Automobili ({cars?.length || 0})
          </button>
          <button
            onClick={() => setActiveTab("blog")}
            className={`px-6 py-3 rounded-lg font-semibold transition ${
              activeTab === "blog"
                ? "bg-blue-600 text-white"
                : "bg-slate-800 text-slate-300 hover:bg-slate-700"
            }`}
          >
            Blog ({posts?.length || 0})
          </button>
          <button
            onClick={() => setActiveTab("messages")}
            className={`px-6 py-3 rounded-lg font-semibold transition ${
              activeTab === "messages"
                ? "bg-blue-600 text-white"
                : "bg-slate-800 text-slate-300 hover:bg-slate-700"
            }`}
          >
            Poruke ({messages?.length || 0})
          </button>
        </div>

        {activeTab === "cars" && (
          <div>
            <div className="mb-6">
              <button
                onClick={() => {
                  setEditingCar(null);
                  setShowCarForm(true);
                }}
                className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg font-semibold flex items-center space-x-2"
              >
                <Plus className="w-5 h-5" />
                <span>Dodaj Automobil</span>
              </button>
            </div>

            {showCarForm && (
              <CarForm
                car={editingCar}
                onClose={() => {
                  setShowCarForm(false);
                  setEditingCar(null);
                }}
              />
            )}

            <div className="grid gap-4">
              {cars?.map((car) => (
                <div key={car.id} className="bg-slate-800 p-6 rounded-lg border border-slate-700">
                  <div className="flex justify-between items-start">
                    <div className="flex space-x-4">
                      <img src={car.image} alt={car.model} className="w-24 h-24 object-cover rounded" />
                      <div>
                        <h3 className="text-xl font-bold">{car.brand} {car.model}</h3>
                        <p className="text-slate-400">{car.year} - {car.category}</p>
                        <p className="text-sm text-slate-500 mt-2">{car.engine} - {car.power}</p>
                      </div>
                    </div>
                    <div className="flex space-x-2">
                      <button
                        onClick={() => {
                          setEditingCar(car);
                          setShowCarForm(true);
                        }}
                        className="p-2 bg-blue-600 hover:bg-blue-700 rounded"
                      >
                        <Edit className="w-5 h-5" />
                      </button>
                      <button
                        onClick={() => confirm("Jeste li sigurni?") && deleteCar.mutate(car.id)}
                        className="p-2 bg-red-600 hover:bg-red-700 rounded"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === "blog" && (
          <div>
            <div className="mb-6">
              <button
                onClick={() => {
                  setEditingBlog(null);
                  setShowBlogForm(true);
                }}
                className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg font-semibold flex items-center space-x-2"
              >
                <Plus className="w-5 h-5" />
                <span>Dodaj Blog Post</span>
              </button>
            </div>

            {showBlogForm && (
              <BlogForm
                post={editingBlog}
                onClose={() => {
                  setShowBlogForm(false);
                  setEditingBlog(null);
                }}
              />
            )}

            <div className="grid gap-4">
              {posts?.map((post) => (
                <div key={post.id} className="bg-slate-800 p-6 rounded-lg border border-slate-700">
                  <div className="flex justify-between items-start">
                    <div className="flex space-x-4">
                      <img src={post.image} alt={post.title} className="w-24 h-24 object-cover rounded" />
                      <div>
                        <h3 className="text-xl font-bold">{post.title}</h3>
                        <p className="text-slate-400">{post.category} - {post.author}</p>
                        <p className="text-sm text-slate-500 mt-2">{new Date(post.date).toLocaleDateString('hr-HR')}</p>
                      </div>
                    </div>
                    <div className="flex space-x-2">
                      <button
                        onClick={() => {
                          setEditingBlog(post);
                          setShowBlogForm(true);
                        }}
                        className="p-2 bg-blue-600 hover:bg-blue-700 rounded"
                      >
                        <Edit className="w-5 h-5" />
                      </button>
                      <button
                        onClick={() => confirm("Jeste li sigurni?") && deleteBlog.mutate(post.id)}
                        className="p-2 bg-red-600 hover:bg-red-700 rounded"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === "messages" && (
          <div className="grid gap-4">
            {messages?.map((message) => (
              <div key={message.id} className="bg-slate-800 p-6 rounded-lg border border-slate-700">
                <div className="mb-2">
                  <h3 className="font-bold">{message.name}</h3>
                  <p className="text-sm text-slate-400">{message.email}</p>
                  <p className="text-xs text-slate-500">{new Date(message.date).toLocaleString('hr-HR')}</p>
                </div>
                <p className="text-slate-300 mt-4">{message.message}</p>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

function CarForm({ car, onClose }: { car: Car | null; onClose: () => void }) {
  const [formData, setFormData] = useState({
    brand: car?.brand || "",
    model: car?.model || "",
    year: car?.year || new Date().getFullYear(),
    description: car?.description || "",
    image: car?.image || "",
    engine: car?.engine || "",
    power: car?.power || "",
    acceleration: car?.acceleration || "",
    consumption: car?.consumption || "",
    driveType: car?.driveType || "",
    category: car?.category || "Compact",
    videoUrl: car?.videoUrl || "",
    reliability: car?.reliability || 3,
  });
  const queryClient = useQueryClient();

  const saveCar = useMutation({
    mutationFn: async (data: typeof formData) => {
      const url = car ? `/api/cars/${car.id}` : "/api/cars";
      const method = car ? "PUT" : "POST";
      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });
      if (!res.ok) throw new Error("Failed to save");
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/cars"] });
      onClose();
    },
  });

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
      <div className="bg-slate-800 rounded-lg p-8 max-w-2xl w-full max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold">{car ? "Uredi" : "Dodaj"} Automobil</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-700 rounded">
            <X className="w-6 h-6" />
          </button>
        </div>

        <form
          onSubmit={(e) => {
            e.preventDefault();
            saveCar.mutate(formData);
          }}
          className="space-y-4"
        >
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-2">Marka</label>
              <input
                type="text"
                value={formData.brand}
                onChange={(e) => setFormData({ ...formData, brand: e.target.value })}
                required
                className="w-full bg-slate-900 border border-slate-700 rounded px-4 py-2"
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-2">Model</label>
              <input
                type="text"
                value={formData.model}
                onChange={(e) => setFormData({ ...formData, model: e.target.value })}
                required
                className="w-full bg-slate-900 border border-slate-700 rounded px-4 py-2"
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-2">Godina</label>
              <input
                type="number"
                value={formData.year}
                onChange={(e) => setFormData({ ...formData, year: parseInt(e.target.value) })}
                required
                className="w-full bg-slate-900 border border-slate-700 rounded px-4 py-2"
              />
            </div>
            <div>
              <label className="block text-sm font-medium mb-2">Kategorija</label>
              <select
                value={formData.category}
                onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                className="w-full bg-slate-900 border border-slate-700 rounded px-4 py-2"
              >
                <option>Compact</option>
                <option>Sedan</option>
                <option>SUV</option>
                <option>Sports</option>
                <option>Electric</option>
              </select>
            </div>
          </div>

          <div>
