import passport from "passport";
import { Strategy as LocalStrategy } from "passport-local";
import { db } from "./db";
import { users, type SafeUser } from "../shared/schema";
import { eq } from "drizzle-orm";
import bcrypt from "bcryptjs";

passport.use(
  new LocalStrategy(
    { usernameField: "email" },
    async (email, password, done) => {
      try {
        const [user] = await db
          .select()
          .from(users)
          .where(eq(users.email, email))
          .limit(1);

        if (!user) {
          return done(null, false, { message: "Invalid email or password" });
        }

        const isValid = await bcrypt.compare(password, user.password);
        if (!isValid) {
          return done(null, false, { message: "Invalid email or password" });
        }

        const { password: _, ...safeUser } = user;
        return done(null, safeUser);
      } catch (error) {
        return done(error);
      }
    }
  )
);

passport.serializeUser((user, done) => {
  done(null, (user as SafeUser).id);
});

passport.deserializeUser(async (id: string, done) => {
  try {
    const [user] = await db
      .select({
        id: users.id,
        email: users.email,
        name: users.name,
        role: users.role,
        createdAt: users.createdAt,
      })
      .from(users)
      .where(eq(users.id, id))
      .limit(1);

    if (!user) {
      return done(null, false);
    }

    done(null, user);
  } catch (error) {
    done(error);
  }
});

export default passport;

server/storage.ts.content:
import { db } from "./db";
import {
  cars,
  blogPosts,
  contactMessages,
  users,
  type InsertCar,
  type InsertBlogPost,
  type InsertContactMessage,
  type InsertUser,
} from "../shared/schema";
import { eq } from "drizzle-orm";
import bcrypt from "bcryptjs";

export const storage = {
  async getCars() {
    return await db.select().from(cars);
  },

  async getCarById(id: string) {
    const [car] = await db.select().from(cars).where(eq(cars.id, id)).limit(1);
    return car;
  },

  async createCar(data: InsertCar) {
    const [car] = await db.insert(cars).values(data).returning();
    return car;
  },

  async updateCar(id: string, data: Partial<InsertCar>) {
    const [car] = await db
      .update(cars)
      .set(data)
      .where(eq(cars.id, id))
      .returning();
    return car;
  },

  async deleteCar(id: string) {
    await db.delete(cars).where(eq(cars.id, id));
  },

  async getBlogPosts() {
    return await db.select().from(blogPosts);
  },

  async getBlogPostById(id: string) {
    const [post] = await db
      .select()
      .from(blogPosts)
      .where(eq(blogPosts.id, id))
      .limit(1);
    return post;
  },

  async createBlogPost(data: InsertBlogPost) {
    const [post] = await db.insert(blogPosts).values(data).returning();
    return post;
  },

  async updateBlogPost(id: string, data: Partial<InsertBlogPost>) {
    const [post] = await db
      .update(blogPosts)
      .set(data)
      .where(eq(blogPosts.id, id))
      .returning();
    return post;
  },

  async deleteBlogPost(id: string) {
    await db.delete(blogPosts).where(eq(blogPosts.id, id));
  },

  async getContactMessages() {
    return await db.select().from(contactMessages);
  },

  async createContactMessage(data: InsertContactMessage) {
    const messageData = {
      ...data,
      date: new Date().toISOString(),
    };
    const [message] = await db
      .insert(contactMessages)
      .values(messageData)
      .returning();
    return message;
  },

  async getUserByEmail(email: string) {
    const [user] = await db
      .select()
      .from(users)
      .where(eq(users.email, email))
      .limit(1);
    return user;
  },

  async createUser(data: InsertUser) {
    const hashedPassword = await bcrypt.hash(data.password, 10);
    const userData = {
      ...data,
      password: hashedPassword,
      role: "user",
    };
    const [user] = await db.insert(users).values(userData).returning();
    const { password: _, ...safeUser } = user;
    return safeUser;
  },
};

