import { useQuery } from "@tanstack/react-query";
import { useLocation, Link, useSearch } from "wouter";
import { ArrowLeft, X } from "lucide-react";
import type { Car } from "@shared/schema";

export default function Compare() {
  const [, setLocation] = useLocation();
  const search = useSearch();

  const searchParams = new URLSearchParams(search);
  const carIds = searchParams.getAll('id');

  const { data: cars = [], isLoading } = useQuery<Car[]>({
    queryKey: ["/api/cars"],
  });

  const selectedCars = cars.filter(car => carIds.includes(car.id));

  const removeCar = (carId: string) => {
    const newIds = carIds.filter(id => id !== carId);
    if (newIds.length === 0) {
      setLocation('/automobili');
    } else {
      setLocation(`/usporedi?${newIds.map(id => `id=${id}`).join('&')}`);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-950">
        <div className="text-center">
          <p className="text-lg text-slate-400">Učitavanje...</p>
        </div>
      </div>
    );
  }

  if (selectedCars.length === 0) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-950">
        <div className="text-center space-y-4">
          <h2 className="text-2xl font-bold text-white">Nema odabranih automobila</h2>
          <p className="text-slate-400">Idite na stranicu automobila i odaberite automobile za usporedbu</p>
          <Link 
            href="/automobili"
            className="inline-flex items-center px-6 py-3 bg-blue-500 hover:bg-blue-600 text-white font-semibold rounded-lg transition-colors"
            data-testid="button-back-to-cars"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Natrag na automobile
          </Link>
        </div>
      </div>
    );
  }

  const specs = [
    { label: "Motor", key: "engine" as keyof Car },
    { label: "Snaga", key: "power" as keyof Car },
    { label: "Ubrzanje 0-100", key: "acceleration" as keyof Car },
    { label: "Potrošnja", key: "consumption" as keyof Car },
    { label: "Pogon", key: "driveType" as keyof Car },
    { label: "Godina", key: "year" as keyof Car },
    { label: "Kategorija", key: "category" as keyof Car },
  ];

  return (
    <div className="min-h-screen bg-slate-950 py-8">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-8">
          <Link 
            href="/automobili"
            className="inline-flex items-center px-4 py-2 text-slate-400 hover:text-white transition-colors"
            data-testid="button-back-to-list"
          >
            <ArrowLeft className="w-4 h-4 mr-2" />
            Natrag na listu
          </Link>
        </div>

        <h1 className="text-4xl font-bold mb-8 text-white" data-testid="text-page-title">
          Usporedba automobila
        </h1>

        <div className="overflow-x-auto">
          <div className="inline-block min-w-full align-middle">
            <div className="grid gap-6" style={{ gridTemplateColumns: `repeat(${selectedCars.length}, minmax(320px, 1fr))` }}>
              {selectedCars.map((car) => (
                <div 
                  key={car.id} 
                  className="bg-slate-800 rounded-xl overflow-hidden shadow-xl"
                  data-testid={`card-compare-${car.id}`}
                >
                  <div className="p-6 relative">
                    <button
                      className="absolute top-4 right-4 p-2 text-slate-400 hover:text-white hover:bg-slate-700 rounded-lg transition-colors"
                      onClick={() => removeCar(car.id)}
                      data-testid={`button-remove-${car.id}`}
                      aria-label="Ukloni automobil"
                    >
                      <X className="w-5 h-5" />
                    </button>

                    <img
                      src={car.image}
                      alt={`${car.brand} ${car.model}`}
                      className="w-full h-48 object-cover rounded-lg mb-4"
                      data-testid={`img-car-${car.id}`}
                    />

                    <h3 className="text-xl font-bold text-white mb-2" data-testid={`text-car-name-${car.id}`}>
                      {car.brand} {car.model}
                    </h3>

                    <span 
                      className="inline-block px-3 py-1 bg-slate-700 text-slate-300 text-sm rounded-full"
                      data-testid={`badge-category-${car.id}`}
                    >
                      {car.category}
                    </span>
                  </div>

                  <div className="p-6 space-y-4 border-t border-slate-700">
                    {specs.map((spec) => (
                      <div key={String(spec.key)} className="flex flex-col">
                        <span className="text-sm text-slate-400 mb-1">{spec.label}</span>
                        <span 
                          className="font-medium text-white" 
                          data-testid={`text-${String(spec.key)}-${car.id}`}
                        >
                          {spec.key === 'year' ? car[spec.key] : car[spec.key] || '-'}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {selectedCars.length < 3 && (
          <div className="mt-8 text-center">
            <p className="text-slate-400 mb-4">
              Možete dodati još {3 - selectedCars.length} {selectedCars.length === 2 ? 'automobil' : 'automobila'} za usporedbu
            </p>
            <Link 
              href="/automobili"
              className="px-6 py-3 border-2 border-blue-500 text-blue-500 hover:bg-blue-500 hover:text-white font-semibold rounded-lg transition-colors"
              data-testid="button-add-more"
            >
              Dodaj automobile
            </Link>
          </div>
        )}
      </div>
    </div>
  );
}
